mapper.select:
SELECT service_id, service_type_id, main_category, image_url, service_name, description, price, estimated_duration,
       available_status, create_time, update_time
FROM service

    AND service_type_id = #{serviceTypeId}
    AND main_category = #{mainCategory}
    AND available_status = #{availableStatus}

ORDER BY service_id

mapper.update:
UPDATE service
service_type_id = #{serviceTypeId}, main_category = #{mainCategory}, image_url = #{imageUrl}, service_name = #{serviceName}, description = #{description}, price = #{price}, estimated_duration = #{estimatedDuration}, available_status = #{availableStatus},
WHERE service_id = #{serviceId}
